use std::fmt::Write;

use proc_macro2::TokenStream;
use quote::{format_ident, quote};
use rust_format::{Formatter, RustFmt};
use weedle::Definition::*;
use weedle::argument::Argument::Single;
use weedle::interface::InterfaceMember;
use weedle::types::ReturnType;

const PREAMBLE: &str = r#"// DO NOT MODIFY!
// This file is generated by tools/glean-sys-parser.
// Run `cargo run -p glean-sys-parser glean-core/src/glean.udl` to regenerate it.

use crate::types::*;
use crate::util::*;
"#;

fn resolve_builtin_type(name: &str) -> Option<TokenStream> {
    match name {
        "string" => Some(quote! { String }),
        "bytes" => Some(quote! { Vec<u8> }),
        "u8" => Some(quote! { u8 }),
        "i8" => Some(quote! { i8 }),
        "u16" => Some(quote! { u16 }),
        "i16" => Some(quote! { i16 }),
        "u32" => Some(quote! { u32 }),
        "i32" => Some(quote! { i32 }),
        "u64" => Some(quote! { u64 }),
        "i64" => Some(quote! { i64 }),
        "f32" => Some(quote! { f32 }),
        "f64" => Some(quote! { f64 }),
        "void" => Some(quote! { () }),
        _ => None,
    }
}

fn resolve_builtin_type_ffi(name: &str) -> Option<TokenStream> {
    match name {
        "string" => Some(quote! { uniffi::RustBuffer }),
        "bytes" => Some(quote! { uniffi::RustBuffer }),
        "u8" => Some(quote! { u8 }),
        "i8" => Some(quote! { i8 }),
        "u16" => Some(quote! { u16 }),
        "i16" => Some(quote! { i16 }),
        "u32" => Some(quote! { u32 }),
        "i32" => Some(quote! { i32 }),
        "u64" => Some(quote! { u64 }),
        "i64" => Some(quote! { i64 }),
        "f32" => Some(quote! { f32 }),
        "f64" => Some(quote! { f64 }),
        "void" => Some(quote! { () }),
        _ => None,
    }
}

trait TypeResolver {
    fn resolve(&self) -> TokenStream;

    fn resolve_ffi(&self) -> TokenStream;
}

impl TypeResolver for &weedle::types::Type<'_> {
    fn resolve(&self) -> TokenStream {
        (*self).resolve()
    }

    fn resolve_ffi(&self) -> TokenStream {
        (*self).resolve_ffi()
    }
}

impl TypeResolver for weedle::types::Type<'_> {
    fn resolve(&self) -> TokenStream {
        match self {
            weedle::types::Type::Single(t) => match t {
                weedle::types::SingleType::Any(_) => panic!("no support for `any` types"),
                weedle::types::SingleType::NonAny(t) => t.resolve(),
            },
            weedle::types::Type::Union(_) => panic!("no support for union types yet"),
        }
    }

    fn resolve_ffi(&self) -> TokenStream {
        match self {
            weedle::types::Type::Single(t) => match t {
                weedle::types::SingleType::Any(_) => panic!("no support for `any` types"),
                weedle::types::SingleType::NonAny(t) => t.resolve_ffi(),
            },
            weedle::types::Type::Union(_) => panic!("no support for union types yet"),
        }
    }
}

impl TypeResolver for weedle::types::NonAnyType<'_> {
    fn resolve(&self) -> TokenStream {
        match self {
            weedle::types::NonAnyType::Boolean(t) => t.resolve(),
            weedle::types::NonAnyType::Identifier(t) => t.resolve(),
            weedle::types::NonAnyType::Integer(t) => t.resolve(),
            weedle::types::NonAnyType::FloatingPoint(t) => t.resolve(),
            weedle::types::NonAnyType::Sequence(t) => t.resolve(),
            weedle::types::NonAnyType::RecordType(t) => t.resolve(),
            _ => panic!("no support for type {:?}", self),
        }
    }

    fn resolve_ffi(&self) -> TokenStream {
        match self {
            weedle::types::NonAnyType::Boolean(t) => t.resolve_ffi(),
            weedle::types::NonAnyType::Identifier(t) => t.resolve_ffi(),
            weedle::types::NonAnyType::Integer(t) => t.resolve_ffi(),
            weedle::types::NonAnyType::FloatingPoint(t) => t.resolve_ffi(),
            weedle::types::NonAnyType::Sequence(t) => t.resolve_ffi(),
            weedle::types::NonAnyType::RecordType(t) => t.resolve_ffi(),
            _ => panic!("no support for type {:?}", self),
        }
    }
}

impl<T: TypeResolver> TypeResolver for weedle::types::MayBeNull<T> {
    fn resolve(&self) -> TokenStream {
        let type_ = self.type_.resolve();
        match self.q_mark {
            None => type_,
            Some(_) => {
                quote! { Option<#type_> }
            }
        }
    }

    fn resolve_ffi(&self) -> TokenStream {
        let type_ = self.type_.resolve_ffi();
        match self.q_mark {
            None => type_,
            Some(_) => {
                quote! { uniffi::RustBuffer }
            }
        }
    }
}

impl TypeResolver for weedle::types::IntegerType {
    fn resolve(&self) -> TokenStream {
        panic!(
            "WebIDL integer types not implemented ({:?}); consider using u8, u16, u32 or u64",
            self
        )
    }
    fn resolve_ffi(&self) -> TokenStream {
        self.resolve()
    }
}

impl TypeResolver for weedle::types::FloatingPointType {
    fn resolve(&self) -> TokenStream {
        match self {
            weedle::types::FloatingPointType::Float(t) => t.resolve(),
            weedle::types::FloatingPointType::Double(t) => t.resolve(),
        }
    }

    fn resolve_ffi(&self) -> TokenStream {
        match self {
            weedle::types::FloatingPointType::Float(t) => t.resolve_ffi(),
            weedle::types::FloatingPointType::Double(t) => t.resolve_ffi(),
        }
    }
}

impl TypeResolver for weedle::types::SequenceType<'_> {
    fn resolve(&self) -> TokenStream {
        let t = self.generics.body.as_ref().resolve();
        quote! { Vec<#t> }
    }

    fn resolve_ffi(&self) -> TokenStream {
        quote! { uniffi::RustBuffer }
    }
}

impl TypeResolver for weedle::types::RecordKeyType<'_> {
    fn resolve(&self) -> TokenStream {
        use weedle::types::RecordKeyType::*;
        match self {
            Byte(_) | USV(_) => panic!(
                "WebIDL Byte or USV string type not implemented ({self:?}); \
                 consider using a string",
            ),
            DOM(_) => quote! { String },
            NonAny(t) => t.resolve(),
        }
    }

    fn resolve_ffi(&self) -> TokenStream {
        use weedle::types::RecordKeyType::*;
        match self {
            Byte(_) | USV(_) => panic!(
                "WebIDL Byte or USV string type not implemented ({self:?}); \
                 consider using a string",
            ),
            DOM(_) => quote! { uniffi::RustBuffer },
            NonAny(t) => t.resolve_ffi(),
        }
    }
}

impl TypeResolver for weedle::types::RecordType<'_> {
    fn resolve(&self) -> TokenStream {
        let key_type = self.generics.body.0.resolve();
        let value_type = self.generics.body.2.resolve();

        quote! { ::std::collections::HashMap<#key_type, #value_type> }
    }

    fn resolve_ffi(&self) -> TokenStream {
        quote! { uniffi::RustBuffer }
    }
}

impl TypeResolver for weedle::common::Identifier<'_> {
    fn resolve(&self) -> TokenStream {
        match resolve_builtin_type(self.0) {
            Some(type_) => type_,
            None => {
                let ident = format_ident!("{}", self.0);
                quote! { #ident }
            }
        }
    }

    fn resolve_ffi(&self) -> TokenStream {
        match resolve_builtin_type_ffi(self.0) {
            Some(type_) => type_,
            None => {
                quote! { uniffi::RustBuffer }
            }
        }
    }
}

impl TypeResolver for weedle::term::Boolean {
    fn resolve(&self) -> TokenStream {
        quote! { i8 }
    }

    fn resolve_ffi(&self) -> TokenStream {
        self.resolve()
    }
}

impl TypeResolver for weedle::types::FloatType {
    fn resolve(&self) -> TokenStream {
        if self.unrestricted.is_some() {
            panic!("we don't support `unrestricted float`");
        }
        quote! { f32 }
    }

    fn resolve_ffi(&self) -> TokenStream {
        self.resolve()
    }
}

impl TypeResolver for weedle::types::DoubleType {
    fn resolve(&self) -> TokenStream {
        if self.unrestricted.is_some() {
            panic!("we don't support `unrestricted double`");
        }
        quote! { f64 }
    }

    fn resolve_ffi(&self) -> TokenStream {
        quote! { bool }
    }
}

fn return_type(typ: &ReturnType) -> TokenStream {
    let ReturnType::Type(typ) = typ else {
        panic!("can't handle undefined return type")
    };
    let ret = typ.resolve();
    quote! { -> #ret }
}

fn return_type_ffi(typ: &ReturnType) -> TokenStream {
    let ReturnType::Type(typ) = typ else {
        panic!("can't handle undefined return type")
    };
    let ret = typ.resolve_ffi();
    quote! { -> #ret }
}

fn main() {
    let file = std::env::args().skip(1).next().unwrap();
    let content = std::fs::read_to_string(&file).unwrap();
    let parsed = weedle::parse(&content).unwrap();

    let mut tokens = vec![];
    let mut bindings = vec![];

    for elem in parsed {
        let Interface(iface) = elem else { continue };
        let ident = iface.identifier;
        if !ident.0.ends_with("Metric") {
            continue;
        }

        let structname = ident.0.to_lowercase().replace("_", "");
        let ident = format_ident!("{}", ident.0);
        let extern_fn_ident = format_ident!("uniffi_glean_core_fn_clone_{}", structname);
        tokens.push(quote! {
            #[derive(uniffi::Record)]
            pub struct #ident {
                handle: u64
            }

            impl #ident {
                unsafe fn clone_handle(&self) -> u64 {
                    let mut call_status = uniffi::RustCallStatus::default();
                    std::mem::transmute((crate::GLEAN.#extern_fn_ident)(std::mem::transmute(self.handle), &mut call_status))
                }
            }
        });
        bindings.push(quote! {
            fn #extern_fn_ident(handle: u64, call_status: &mut ::uniffi::RustCallStatus) -> u64;
        });


        let mut fns = vec![];
        let members = iface.members;
        for member in members.body {
            match member {
                InterfaceMember::Constructor(_ctor) => {
                    let extern_fn_ident = format_ident!("uniffi_glean_core_fn_constructor_{}_new", structname);
                    fns.push(quote! {
                        pub fn new(meta: CommonMetricData) -> Self {
                            unsafe {
                                let meta = uniffi::FfiConverter::<crate::UniFfiTag>::lower(meta);
                                let mut call_status = uniffi::RustCallStatus::default();
                                let handle = (crate::GLEAN.#extern_fn_ident)(meta.clone_for_ffi(), &mut call_status);
                                Self { handle }
                            }
                        }
                    });
                    bindings.push(quote! {
                        fn #extern_fn_ident(meta: uniffi::RustBuffer, call_status: &mut ::uniffi::RustCallStatus) -> u64;
                    });
                }
                InterfaceMember::Operation(op) => {
                    let Some(ident) = op.identifier else {
                        panic!("no identifier for op!")
                    };
                    let fn_ident = format_ident!("{}", ident.0);
                    let extern_fn_ident = format_ident!("uniffi_glean_core_fn_method_{}_{}", structname, ident.0);
                    let ret_type = return_type(&op.return_type);
                    let extern_fn_ret_type = return_type_ffi(&op.return_type);

                    let args = op.args.body.list;
                    let mut fn_args = Vec::with_capacity(args.len());
                    let mut extern_fn_args = Vec::with_capacity(args.len());
                    let mut arg_names = Vec::with_capacity(args.len());
                    let mut buffer_drops = Vec::with_capacity(args.len());

                    for arg in args {
                        let Single(arg) = arg else { continue };
                        let arg_name = format_ident!("{}", arg.identifier.0);
                        let arg_type = arg.type_.type_.resolve();
                        let extern_arg_type = arg.type_.type_.resolve_ffi();
                        arg_names.push(quote! { #arg_name });
                        fn_args.push(quote! { #arg_name: #arg_type });
                        extern_fn_args.push(quote! { #arg_name: #extern_arg_type });
                        if extern_arg_type.to_string() == "RustBuffer" {
                            buffer_drops.push(quote! { #arg_name.destroy(); })
                        }
                    }
                    buffer_drops.reverse();
                    fns.push(quote! {
                        pub fn #fn_ident(&self, #(#fn_args),*) #ret_type {
                            unsafe {
                                let this = self.clone_handle();
                                #(
                                    let #arg_names = uniffi::FfiConverter::<crate::UniFfiTag>::lower(#arg_names);
                                )*
                                let mut call_status = uniffi::RustCallStatus::default();
                                let res = (crate::GLEAN.#extern_fn_ident)(this, #(#arg_names.clone_for_ffi(),)* &mut call_status);
                                uniffi::FfiConverter::<crate::UniFfiTag>::try_lift(res).unwrap()
                            }
                        }
                    });
                    bindings.push(quote! {
                        fn #extern_fn_ident(handle: u64, #(#extern_fn_args,)* call_status: &mut ::uniffi::RustCallStatus) #extern_fn_ret_type;
                    });
                }
                _ => todo!(),
            }
        }

        tokens.push(quote! {
            impl #ident {
                #(#fns)*
            }
        });
    }

    tokens.push(quote! {
        library_binding! {
            #(#bindings)*
        }
    });

    let mut code = String::new();
    for token in tokens {
        writeln!(&mut code, "{token}").unwrap();
    }

    println!("{PREAMBLE}");
    let code = RustFmt::default().format_str(code).unwrap();
    println!("{code}");
}
